insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 0, 'Find the LCM of 18 and 24.', '18 और 24 का LCM ज्ञात कीजिए।', 'Use LCM × HCF = product. HCF(18,24) = 6. LCM = 18×24/6 = 72. Therefore, answer = 72.', 'For two positive integers, HCF captures the common part and LCM captures each prime factor at its maximum power. Their product equals the product of the two numbers. Final answer is 72.', 'LCM × HCF = product लगाएँ। HCF(18,24) = 6। LCM = 18×24/6 = 72। अतः answer = 72।', 'दो positive integers में HCF common part लेता है और LCM हर prime factor की maximum power लेता है। इसलिए LCM × HCF = product। Final answer 72 है।', 'EASY', array['number-system','lcm-hcf']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '72', '72', true, null, null);
