insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 1, 'Find the LCM of 28 and 42.', '28 और 42 का LCM ज्ञात कीजिए।', 'Use LCM × HCF = product. HCF(28,42) = 14. LCM = 28×42/14 = 84. Therefore, answer = 84.', 'For two positive integers, HCF captures the common part and LCM captures each prime factor at its maximum power. Their product equals the product of the two numbers. Final answer is 84.', 'LCM × HCF = product लगाएँ। HCF(28,42) = 14। LCM = 28×42/14 = 84। अतः answer = 84।', 'दो positive integers में HCF common part लेता है और LCM हर prime factor की maximum power लेता है। इसलिए LCM × HCF = product। Final answer 84 है।', 'EASY', array['number-system','lcm-hcf']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
