insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 2, 'Find the LCM of 36 and 60.', '36 और 60 का LCM ज्ञात कीजिए।', 'Use LCM × HCF = product. HCF(36,60) = 12. LCM = 36×60/12 = 180. Therefore, answer = 180.', 'For two positive integers, HCF captures the common part and LCM captures each prime factor at its maximum power. Their product equals the product of the two numbers. Final answer is 180.', 'LCM × HCF = product लगाएँ। HCF(36,60) = 12। LCM = 36×60/12 = 180। अतः answer = 180।', 'दो positive integers में HCF common part लेता है और LCM हर prime factor की maximum power लेता है। इसलिए LCM × HCF = product। Final answer 180 है।', 'EASY', array['number-system','lcm-hcf']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
