insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 4, 'Find the LCM of 32 and 48.', '32 और 48 का LCM ज्ञात कीजिए।', 'Use LCM × HCF = product. HCF(32,48) = 16. LCM = 32×48/16 = 96. Therefore, answer = 96.', 'For two positive integers, HCF captures the common part and LCM captures each prime factor at its maximum power. Their product equals the product of the two numbers. Final answer is 96.', 'LCM × HCF = product लगाएँ। HCF(32,48) = 16। LCM = 32×48/16 = 96। अतः answer = 96।', 'दो positive integers में HCF common part लेता है और LCM हर prime factor की maximum power लेता है। इसलिए LCM × HCF = product। Final answer 96 है।', 'EASY', array['number-system','lcm-hcf']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
