insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 6, 'Find the HCF of 96 and 160.', '96 और 160 का HCF ज्ञात कीजिए।', 'Euclid method: repeatedly subtract/reduce common parts; HCF(96,160) = 32. Therefore, answer = 32.', 'HCF is the largest number that divides both given numbers exactly. Prime factorisation or Euclid''s algorithm both isolate this common divisor. Final answer is 32.', 'Euclid method से common divisor निकालें; HCF(96,160) = 32। अतः answer = 32।', 'HCF सबसे बड़ी संख्या है जो दोनों numbers को exactly divide करती है। Prime factorisation या Euclid method दोनों same common divisor देते हैं। Final answer 32 है।', 'EASY', array['number-system','lcm-hcf']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
