insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 21, 'The first part of a quantity is 630, and it is 9 times the second part. Find the second part.', 'किसी quantity का पहला भाग 630 है और यह दूसरे भाग का 9 गुना है। दूसरा भाग ज्ञात कीजिए।', 'Let the second part be x. First part = 9x = 630; so x = 630/9 = 70. Therefore, answer = 70.', 'When one quantity is described as a multiple of another, assign the smaller unknown as x and translate the sentence into an equation before choosing the asked part. Final answer is 70.', 'दूसरा भाग x मानें। पहला भाग = 9x = 630; इसलिए x = 630/9 = 70। अतः answer = 70।', 'जब एक quantity दूसरी की multiple हो, smaller unknown को x मानकर equation बनाते हैं और पूछा गया part निकालते हैं। Final answer 70 है।', 'HARD', array['number-system','ratio-basics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
